# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balances(transactions, initial_balances):
    updated_balances = initial_balances.copy()
    
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        
        if transaction['type'] == 'deposit':
            updated_balances[account_id] += amount
        elif transaction['type'] == 'withdrawal':
            updated_balances[account_id] -= amount
    
    return updated_balances

# Example usage:
transactions = [
    {'account_id': 1, 'type': 'deposit', 'amount': 100},
    {'account_id': 2, 'type': 'withdrawal', 'amount': 50},
    {'account_id': 1, 'type': 'withdrawal', 'amount': 30}
]

initial_balances = {
    1: 500,
    2: 300
}

updated_balances = update_account_balances(transactions, initial_balances)
print(updated_balances)